  1→/**
  2→ * Observer agent: verifies entity state changes and surfaces observations.
  3→ *
  4→ * Follows the same structural pattern as agents/pm/agent.ts.
  5→ * Currently operates deterministically using the verification pipeline.
  6→ * Future milestones may introduce LLM-based reasoning via ToolLoopAgent.
  7→ *
  8→ * Pipeline: receive event -> load workspace context -> verify claim vs reality -> create observation
  9→ */
 10→
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import { createObservation } from "../../observation/queries";
 13→import { gatherTaskSignals } from "../../observer/external-signals";
 14→import { compareTaskCompletion, type VerificationResult } from "../../observer/verification-pipeline";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ObserverVerdict = "match" | "mismatch" | "inconclusive";
 21→
 22→export type ObserverAgentOutput = {
 23→  observations_created: number;
 24→  verdict: ObserverVerdict;
 25→  evidence: string[];
 26→};
 27→
 28→export type ObserverAgentInput = {
 29→  surreal: Surreal;
 30→  workspaceRecord: RecordId<"workspace", string>;
 31→  entityTable: string;
 32→  entityId: string;
 33→  entityBody?: Record<string, unknown>;
 34→};
 35→
 36→// ---------------------------------------------------------------------------
 37→// Agent entry point
 38→// ---------------------------------------------------------------------------
 39→
 40→export async function runObserverAgent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 41→  const { surreal, workspaceRecord, entityTable, entityId } = input;
 42→
 43→  // Dispatch to entity-specific verification
 44→  switch (entityTable) {
 45→    case "task":
 46→      return verifyTaskCompletion(surreal, workspaceRecord, entityId);
 47→    default:
 48→      return {
 49→        observations_created: 0,
 50→        verdict: "inconclusive",
 51→        evidence: [`Entity type '${entityTable}' verification not yet implemented`],
 52→      };
 53→  }
 54→}
 55→
 56→// ---------------------------------------------------------------------------
 57→// Task verification
 58→// ---------------------------------------------------------------------------
 59→
 60→async function verifyTaskCompletion(
 61→  surreal: Surreal,
 62→  workspaceRecord: RecordId<"workspace", string>,
 63→  taskId: string,
 64→): Promise<ObserverAgentOutput> {
 65→  const taskRecord = new RecordId("task", taskId);
 66→  const evidence: string[] = [];
 67→
 68→  // Gather external signals (commits, CI)
 69→  const signalsResult = await gatherTaskSignals(surreal, taskId);
 70→  evidence.push(`Commits found: ${signalsResult.hasCommits}`);
 71→  evidence.push(`Signal count: ${signalsResult.signals.length}`);
 72→
 73→  // Run pure comparison
 74→  const verificationResult = compareTaskCompletion(signalsResult);
 75→  evidence.push(`Verdict: ${verificationResult.verdict}`);
 76→  evidence.push(verificationResult.text);
 77→
 78→  // Persist observation with observes edge
 79→  await persistVerificationObservation(
 80→    surreal,
 81→    workspaceRecord,
 82→    taskRecord,
 83→    verificationResult,
 84→  );
 85→
 86→  return {
 87→    observations_created: 1,
 88→    verdict: verificationResult.verdict,
 89→    evidence,
 90→  };
 91→}
 92→
 93→// ---------------------------------------------------------------------------
 94→// Observation persistence
 95→// ---------------------------------------------------------------------------
 96→
 97→async function persistVerificationObservation(
 98→  surreal: Surreal,
 99→  workspaceRecord: RecordId<"workspace", string>,
100→  relatedRecord: RecordId,
101→  verificationResult: VerificationResult,
102→): Promise<void> {
103→  const now = new Date();
104→
105→  const observationRecord = await createObservation({
106→    surreal,
107→    workspaceRecord,
108→    text: verificationResult.text,
109→    severity: verificationResult.severity,
110→    sourceAgent: "observer_agent",
111→    observationType: "validation",
112→    now,
113→    relatedRecord: relatedRecord as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
114→  });
115→
116→  // Set verified and source fields
117→  await surreal.query(
118→    `UPDATE $obs SET verified = $verified, source = $source;`,
119→    {
120→      obs: observationRecord,
121→      verified: verificationResult.verified,
122→      source: verificationResult.source ?? "none",
123→    },
124→  );
125→}
