  1→/**
  2→ * Observer HTTP route: POST /api/observe/:table/:id
  3→ *
  4→ * Effect shell that wires the verification pipeline to SurrealDB.
  5→ * Called by SurrealDB EVENTs when entity state transitions occur.
  6→ *
  7→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> persistObservation
  8→ */
  9→
 10→import { RecordId, type Surreal } from "surrealdb";
 11→import { jsonResponse } from "../http/response";
 12→import { logError, logInfo } from "../http/observability";
 13→import { createObservation } from "../observation/queries";
 14→import { checkCiStatus } from "./external-signals";
 15→import { compareIntentCompletion, compareCommitStatus, compareDecisionConfirmation, compareObservationPeerReview } from "./verification-pipeline";
 16→import type { IntentSignals, DecisionSignals, ObservationPeerReviewSignals, VerificationResult } from "./verification-pipeline";
 17→import type { ServerDependencies } from "../runtime/types";
 18→import { runObserverAgent } from "../agents/observer/agent";
 19→import { runGraphScan } from "./graph-scan";
 20→
 21→// ---------------------------------------------------------------------------
 22→// Types
 23→// ---------------------------------------------------------------------------
 24→
 25→type SupportedTable = "task" | "intent" | "git_commit" | "decision" | "observation";
 26→
 27→const SUPPORTED_TABLES = new Set<string>([
 28→  "task",
 29→  "intent",
 30→  "git_commit",
 31→  "decision",
 32→  "observation",
 33→]);
 34→
 35→// ---------------------------------------------------------------------------
 36→// Shared observation persistence
 37→// ---------------------------------------------------------------------------
 38→
 39→async function persistVerificationObservation(
 40→  surreal: Surreal,
 41→  workspaceRecord: RecordId<"workspace", string>,
 42→  relatedRecord: RecordId,
 43→  verificationResult: VerificationResult,
 44→  defaultSource = "none",
 45→): Promise<void> {
 46→  const now = new Date();
 47→
 48→  const observationRecord = await createObservation({
 49→    surreal,
 50→    workspaceRecord,
 51→    text: verificationResult.text,
 52→    severity: verificationResult.severity,
 53→    sourceAgent: "observer_agent",
 54→    observationType: "validation",
 55→    now,
 56→    relatedRecord: relatedRecord as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
 57→  });
 58→
 59→  await surreal.query(
 60→    `UPDATE $obs SET verified = $verified, source = $source;`,
 61→    {
 62→      obs: observationRecord,
 63→      verified: verificationResult.verified,
 64→      source: verificationResult.source ?? defaultSource,
 65→    },
 66→  );
 67→}
 68→
 69→// ---------------------------------------------------------------------------
 70→// Route handler factory
 71→// ---------------------------------------------------------------------------
 72→
 73→export function createObserverRouteHandler(deps: ServerDependencies) {
 74→  return async (table: string, id: string, request: Request): Promise<Response> => {
 75→    if (!SUPPORTED_TABLES.has(table)) {
 76→      return jsonResponse({ error: "unsupported_table", table }, 400);
 77→    }
 78→
 79→    const supportedTable = table as SupportedTable;
 80→
 81→    try {
 82→      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
 83→      const body = await request.json().catch(() => undefined);
 84→
 85→      logInfo("observer.event.received", "Observer event received", {
 86→        table: supportedTable,
 87→        id,
 88→      });
 89→
 90→      // Dispatch to the appropriate verification pipeline
 91→      switch (supportedTable) {
 92→        case "task":
 93→          await handleTaskVerification(deps, id, body);
 94→          break;
 95→
 96→        case "intent":
 97→          await handleIntentVerification(deps, id, body);
 98→          break;
 99→
100→        case "git_commit":
101→          await handleCommitVerification(deps, id, body);
102→          break;
103→
104→        case "decision":
105→          await handleDecisionVerification(deps, id, body);
106→          break;
107→
108→        case "observation":
109→          await handleObservationPeerReview(deps, id, body);
110→          break;
111→      }
112→
113→      return jsonResponse({ status: "ok" }, 200);
114→    } catch (error) {
115→      logError("observer.event.error", "Observer event processing failed", error);
116→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
117→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
118→    }
119→  };
120→}
