122→// ---------------------------------------------------------------------------
123→// Task verification pipeline (effect shell)
124→// ---------------------------------------------------------------------------
125→
126→async function handleTaskVerification(
127→  deps: ServerDependencies,
128→  taskId: string,
129→  body?: Record<string, unknown>,
130→): Promise<void> {
131→  const { surreal } = deps;
132→
133→  // Resolve workspace from the task record body or by querying
134→  const workspaceId = await resolveWorkspaceId(surreal, "task", taskId, body);
135→  if (!workspaceId) {
136→    logError("observer.task.no_workspace", "Cannot determine workspace for task", { taskId });
137→    return;
138→  }
139→
140→  const workspaceRecord = new RecordId("workspace", workspaceId);
141→
142→  // Delegate to observer agent
143→  const agentOutput = await runObserverAgent({
144→    surreal,
145→    workspaceRecord,
146→    entityTable: "task",
147→    entityId: taskId,
148→    entityBody: body,
149→  });
150→
151→  logInfo("observer.task.verified", "Task verification complete", {
152→    taskId,
153→    verdict: agentOutput.verdict,
154→    observationsCreated: agentOutput.observations_created,
155→    evidence: agentOutput.evidence,
156→  });
157→}
158→
159→// ---------------------------------------------------------------------------
160→// Intent verification pipeline (effect shell)
161→// ---------------------------------------------------------------------------
162→
163→async function handleIntentVerification(
164→  deps: ServerDependencies,
165→  intentId: string,
166→  body?: Record<string, unknown>,
167→): Promise<void> {
168→  const { surreal } = deps;
169→
170→  const workspaceId = await resolveWorkspaceId(surreal, "intent", intentId, body);
171→  if (!workspaceId) {
172→    logError("observer.intent.no_workspace", "Cannot determine workspace for intent", { intentId });
173→    return;
174→  }
175→
176→  const workspaceRecord = new RecordId("workspace", workspaceId);
177→  const intentRecord = new RecordId("intent", intentId);
178→
179→  // Gather intent signals: status and trace presence
180→  const intentSignals = await gatherIntentSignals(surreal, intentId, body);
181→  const verificationResult = compareIntentCompletion(intentSignals);
182→
183→  await persistVerificationObservation(surreal, workspaceRecord, intentRecord, verificationResult);
184→
185→  logInfo("observer.intent.verified", "Intent verification complete", {
186→    intentId,
187→    verdict: verificationResult.verdict,
188→    severity: verificationResult.severity,
189→    verified: verificationResult.verified,
190→  });
191→}
192→
193→async function gatherIntentSignals(
194→  surreal: Surreal,
195→  intentId: string,
196→  body?: Record<string, unknown>,
197→): Promise<IntentSignals> {
198→  // Prefer body (from EVENT payload) for status and goal
199→  const status = (body?.status as string) ?? "unknown";
200→  const goal = (body?.goal as string) ?? "Unknown intent";
201→
202→  // Check if a trace exists
203→  const intentRecord = new RecordId("intent", intentId);
204→  const [traceRows] = await surreal.query<[Array<{ trace_id?: RecordId }>]>(
205→    `SELECT trace_id FROM $intent;`,
206→    { intent: intentRecord },
207→  );
208→
209→  const hasTrace = !!traceRows?.[0]?.trace_id;
210→
211→  return { status, goal, hasTrace };
212→}
213→
214→// ---------------------------------------------------------------------------
215→// Commit verification pipeline (effect shell)
216→// ---------------------------------------------------------------------------
217→
218→async function handleCommitVerification(
219→  deps: ServerDependencies,
220→  commitId: string,
221→  body?: Record<string, unknown>,
222→): Promise<void> {
223→  const { surreal } = deps;
224→
225→  const workspaceId = await resolveWorkspaceId(surreal, "git_commit", commitId, body);
226→  if (!workspaceId) {
227→    logError("observer.commit.no_workspace", "Cannot determine workspace for commit", { commitId });
228→    return;
229→  }
230→
231→  const workspaceRecord = new RecordId("workspace", workspaceId);
232→  const commitRecord = new RecordId("git_commit", commitId);
233→
234→  // Gather CI signals for this commit
235→  const sha = (body?.sha as string) ?? "";
236→  const repository = (body?.repository as string) ?? "";
237→
238→  const signal = await checkCiStatus({
239→    id: commitRecord,
240→    sha,
241→    repository,
242→  });
243→
244→  const signalsResult = {
245→    signals: [signal],
246→    hasCommits: true,
247→  };
248→
249→  const verificationResult = compareCommitStatus(signalsResult);
250→
251→  await persistVerificationObservation(surreal, workspaceRecord, commitRecord, verificationResult);
252→
253→  logInfo("observer.commit.verified", "Commit verification complete", {
254→    commitId,
255→    verdict: verificationResult.verdict,
256→    severity: verificationResult.severity,
257→    verified: verificationResult.verified,
258→  });
259→}
260→
261→// ---------------------------------------------------------------------------
262→// Decision verification pipeline (effect shell)
263→// ---------------------------------------------------------------------------
264→
265→async function handleDecisionVerification(
266→  deps: ServerDependencies,
267→  decisionId: string,
268→  body?: Record<string, unknown>,
269→): Promise<void> {
270→  const { surreal } = deps;
271→
272→  // Skip initial CREATE events -- only verify actual status transitions (UPDATEs).
273→  // CREATE events have no updated_at field; UPDATE always sets updated_at via time::now().
274→  if (!body?.updated_at) {
275→    logInfo("observer.decision.skipped_create", "Skipping decision CREATE event (not a status transition)", { decisionId });
276→    return;
277→  }
278→
279→  const workspaceId = await resolveWorkspaceId(surreal, "decision", decisionId, body);
280→  if (!workspaceId) {
281→    logError("observer.decision.no_workspace", "Cannot determine workspace for decision", { decisionId });
282→    return;
283→  }
284→
285→  const workspaceRecord = new RecordId("workspace", workspaceId);
286→  const decisionRecord = new RecordId("decision", decisionId);
287→
288→  // Gather decision signals: status, summary, and completed task count
289→  const decisionSignals = await gatherDecisionSignals(surreal, workspaceRecord, body);
290→  const verificationResult = compareDecisionConfirmation(decisionSignals);
291→
292→  await persistVerificationObservation(surreal, workspaceRecord, decisionRecord, verificationResult);
293→
294→  logInfo("observer.decision.verified", "Decision verification complete", {
295→    decisionId,
296→    verdict: verificationResult.verdict,
297→    severity: verificationResult.severity,
298→    verified: verificationResult.verified,
299→  });
300→}
