302→// ---------------------------------------------------------------------------
303→// Observation peer review pipeline (effect shell)
304→// ---------------------------------------------------------------------------
305→
306→async function handleObservationPeerReview(
307→  deps: ServerDependencies,
308→  observationId: string,
309→  body?: Record<string, unknown>,
310→): Promise<void> {
311→  const { surreal } = deps;
312→
313→  const workspaceId = await resolveWorkspaceId(surreal, "observation", observationId, body);
314→  if (!workspaceId) {
315→    logError("observer.observation.no_workspace", "Cannot determine workspace for observation", { observationId });
316→    return;
317→  }
318→
319→  const workspaceRecord = new RecordId("workspace", workspaceId);
320→  const originalObservationRecord = new RecordId("observation", observationId);
321→
322→  // Gather peer review signals from the original observation and workspace context
323→  const peerReviewSignals = await gatherObservationPeerReviewSignals(surreal, workspaceRecord, body);
324→  const verificationResult = compareObservationPeerReview(peerReviewSignals);
325→
326→  await persistVerificationObservation(surreal, workspaceRecord, originalObservationRecord, verificationResult, "peer_review");
327→
328→  logInfo("observer.observation.peer_reviewed", "Observation peer review complete", {
329→    observationId,
330→    verdict: verificationResult.verdict,
331→    severity: verificationResult.severity,
332→  });
333→}
334→
335→async function gatherObservationPeerReviewSignals(
336→  surreal: Surreal,
337→  workspaceRecord: RecordId<"workspace", string>,
338→  body?: Record<string, unknown>,
339→): Promise<ObservationPeerReviewSignals> {
340→  const originalText = (body?.text as string) ?? "Unknown observation";
341→  const originalSeverity = ((body?.severity as string) ?? "info") as "info" | "warning" | "conflict";
342→  const sourceAgent = (body?.source_agent as string) ?? "unknown_agent";
343→
344→  // Count tasks and decisions in the workspace for cross-checking context
345→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
346→    `SELECT count() AS count FROM task WHERE workspace = $ws GROUP ALL;`,
347→    { ws: workspaceRecord },
348→  );
349→
350→  const [decisionRows] = await surreal.query<[Array<{ count: number }>]>(
351→    `SELECT count() AS count FROM decision WHERE workspace = $ws GROUP ALL;`,
352→    { ws: workspaceRecord },
353→  );
354→
355→  return {
356→    originalText,
357→    originalSeverity,
358→    sourceAgent,
359→    relatedTaskCount: taskRows?.[0]?.count ?? 0,
360→    relatedDecisionCount: decisionRows?.[0]?.count ?? 0,
361→  };
362→}
363→
364→async function gatherDecisionSignals(
365→  surreal: Surreal,
366→  workspaceRecord: RecordId<"workspace", string>,
367→  body?: Record<string, unknown>,
368→): Promise<DecisionSignals> {
369→  const status = (body?.status as string) ?? "unknown";
370→  const summary = (body?.summary as string) ?? "Unknown decision";
371→
372→  // Count completed tasks in the workspace
373→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
374→    `SELECT count() AS count FROM task WHERE workspace = $ws AND (status = "completed" OR status = "done") GROUP ALL;`,
375→    { ws: workspaceRecord },
376→  );
377→
378→  const completedTaskCount = taskRows?.[0]?.count ?? 0;
379→
380→  return { status, summary, completedTaskCount };
381→}
