383→// ---------------------------------------------------------------------------
384→// Graph scan route handler factory
385→// ---------------------------------------------------------------------------
386→
387→export function createGraphScanRouteHandler(deps: ServerDependencies) {
388→  return async (workspaceId: string, _request: Request): Promise<Response> => {
389→    try {
390→      logInfo("observer.scan.started", "Graph scan triggered", { workspaceId });
391→
392→      const workspaceRecord = new RecordId("workspace", workspaceId);
393→      const result = await runGraphScan(deps.surreal, workspaceRecord);
394→
395→      return jsonResponse({
396→        status: "ok",
397→        ...result,
398→      }, 200);
399→    } catch (error) {
400→      logError("observer.scan.error", "Graph scan failed", error);
401→      return jsonResponse({ status: "error", message: "scan failed" }, 500);
402→    }
403→  };
404→}
